const item = $input.first().json;
const body = item.text || item.textPlain || item.snippet || item.body || '';
const sender = item.from || item.From || item.sender || '';
return [{ json: { original_inquiry: body, sender_email: sender, subject: item.subject || item.Subject || 'Customer inquiry', message_id: item.id || item.messageId || item.message_id || '', source_channel: 'gmail', execution_meta: { started_at: new Date().toISOString(), agent_durations: {} } } }];

const raw = $input.first().json.choices?.[0]?.message?.content || $input.first().json.output || $input.first().json.message?.content || '';
function extractJSON(text) { try { return JSON.parse(text.trim()); } catch {} const stripped = text.replace(/```(?:json)?\s*|\s*```/g, '').trim(); try { return JSON.parse(stripped); } catch {} const m1 = text.match(/\{[^{}]*\}/s); if (m1) { try { return JSON.parse(m1[0]); } catch {} } const m2 = text.match(/\{.*\}/s); if (m2) { try { return JSON.parse(m2[0]); } catch {} } return null; }
const parsed = extractJSON(raw);
const ok = !!parsed && ['type','priority','confidence'].every((key) => parsed[key] !== undefined);
const base = $('Normalize_Input').first().json;
return [{ json: { ...base, classification: parsed || {}, _ok: ok, _agent: 'classifier', _raw: ok ? undefined : raw.substring(0, 500) } }];

